function fib(n) {
    if (n < 2) return n;
    return fib(n - 1) + fib(n - 2);
}

const n = parseInt(process.argv[2]);
console.log(fib(n));

function solve(row, cols, diag1, diag2, n) {
    if (row === n) return 1;
    let count = 0;
    let available = ((1 << n) - 1) & ~(cols | diag1 | diag2);
    while (available) {
        const bit = available & (-available);
        available ^= bit;
        count += solve(row + 1, cols | bit, (diag1 | bit) << 1, (diag2 | bit) >> 1, n);
    }
    return count;
}
const n = parseInt(process.argv[2]);
console.log(solve(0, 0, 0, 0, n));

const n = parseInt(process.argv[2]);
const perm1 = Array.from({length: n}, (_, i) => i);
const count = new Array(n).fill(0);
let maxFlips = 0, checksum = 0, permCount = 0, r = n;
outer: while (true) {
    while (r > 1) { count[r-1] = r; r--; }
    const perm = [...perm1];
    let flips = 0;
    while (perm[0] !== 0) {
        const k = perm[0] + 1;
        for (let i = 0; i < k >> 1; i++) { const t = perm[i]; perm[i] = perm[k-1-i]; perm[k-1-i] = t; }
        flips++;
    }
    if (flips > maxFlips) maxFlips = flips;
    checksum += (permCount % 2 === 0) ? flips : -flips;
    permCount++;
    while (true) {
        if (r === n) break outer;
        const p0 = perm1[0];
        for (let i = 0; i < r; i++) perm1[i] = perm1[i+1];
        perm1[r] = p0;
        if (--count[r] > 0) break;
        r++;
    }
}
console.log(checksum + "\n" + maxFlips);

function gcd(a, b) {
    while (b > 0) { const t = b; b = a % b; a = t; }
    return a;
}
const n = parseInt(process.argv[2]);
let sum = 0;
for (let i = 1; i <= n; i++)
    for (let j = i; j <= n; j++)
        sum += gcd(i, j);
console.log(sum);

function makeCheck(d) { return d === 0 ? 1 : 1 + makeCheck(d-1) + makeCheck(d-1); }
const n = parseInt(process.argv[2]), mn = 4;
let mx = Math.max(mn + 2, n);
console.log(`stretch tree of depth ${mx+1}\t check: ${makeCheck(mx+1)}`);
const ll = makeCheck(mx);
for (let d = mn; d <= mx; d += 2) {
    const it = 1 << (mx - d + mn); let tc = 0;
    for (let i = 0; i < it; i++) tc += makeCheck(d);
    console.log(`${it}\t trees of depth ${d}\t check: ${tc}`);
}
console.log(`long lived tree of depth ${mx}\t check: ${ll}`);

const n = parseInt(process.argv[2]);
let total = 0;
for (let i = 1; i <= n; i++) {
    let k = i;
    while (k !== 1) {
        if (k % 2 === 0) k = k / 2;
        else k = 3 * k + 1;
        total++;
    }
}
console.log(total);

